import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { StandardsData, AuditInfo, AuditScope, Standard, MatrixRow, EvidenceTag, AnalysisResult } from '../types';
import { DEFAULT_AUDIT_INFO, STANDARDS_DATA, INITIAL_EVIDENCE } from '../constants';
import { KnowledgeStore } from '../services/knowledgeStore';

interface AuditContextType {
    // Standard
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (key: string) => void;
    customStandards: StandardsData;
    addCustomStandard: (key: string, std: Standard) => void;
    updateStandard: (std: Standard) => void;
    resetStandard: (key: string) => void;

    // Audit Info
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;

    // Scopes (Departments)
    scopes: AuditScope[];
    activeScopeId: string;
    activeScope: AuditScope | undefined;
    setActiveScopeId: (id: string) => void;
    addScope: (name: string) => void;
    renameScope: (id: string, name: string) => void;
    deleteScope: (id: string) => void;

    // Active Data (Derived from activeScope)
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    evidenceTags: EvidenceTag[];
    addEvidenceTag: (tag: EvidenceTag) => void;

    // Selections
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;

    // Knowledge Base
    knowledgeBase: string | null;
    knowledgeFileName: string | null;
    loadKnowledgeForStandard: (key: string) => Promise<void>;
    clearKnowledge: () => void;
    setKnowledgeData: (content: string, fileName: string) => void;

    // Results
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    finalReportText: string | null;
    setFinalReportText: (text: string | null) => void;

    // Actions
    resetSession: () => void;
    restoreSession: (data: any) => void;
}

const AuditContext = createContext<AuditContextType | undefined>(undefined);

export const AuditProvider = ({ children }: { children: ReactNode }) => {
    // --- STATE ---
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);

    // Scopes
    const [scopes, setScopes] = useState<AuditScope[]>([
        { id: "scope_default", name: "", evidence: "", matrixData: {}, evidenceTags: [], uploadedFiles: [] }
    ]);
    const [activeScopeId, setActiveScopeId] = useState<string>("scope_default");

    // Active View Data (Synced with Active Scope)
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [matrixData, setMatrixData] = useState<Record<string, MatrixRow[]>>({});
    const [evidenceTags, setEvidenceTags] = useState<EvidenceTag[]>([]);

    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // KB
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    // Analysis
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);

    const standards = { ...STANDARDS_DATA, ...customStandards };
    const activeScope = scopes.find(s => s.id === activeScopeId);

    // --- SYNC EFFECTS ---
    // Save current view state to the active scope object whenever it changes
    useEffect(() => {
        setScopes(prev => prev.map(s => {
            if (s.id === activeScopeId) {
                // Only update if changed to avoid reference cycling
                if (s.evidence !== evidence || s.matrixData !== matrixData || s.evidenceTags !== evidenceTags) {
                    return { ...s, evidence, matrixData, evidenceTags };
                }
            }
            return s;
        }));
    }, [evidence, matrixData, evidenceTags, activeScopeId]);

    // Load scope data into view when ID changes
    useEffect(() => {
        const target = scopes.find(s => s.id === activeScopeId);
        if (target) {
            setEvidence(target.evidence || "");
            setMatrixData(target.matrixData || {});
            setEvidenceTags(target.evidenceTags || []);
        }
    }, [activeScopeId]); 

    // --- ACTIONS ---

    const addCustomStandard = (key: string, std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [key]: std }));
    };

    const updateStandard = (std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    };

    const resetStandard = (key: string) => {
        setCustomStandards(prev => {
            const next = { ...prev };
            delete next[key];
            return next;
        });
    };

    const addScope = (name: string) => {
        const newId = `scope_${Date.now()}`;
        setScopes(prev => [...prev, { 
            id: newId, 
            name, 
            evidence: "", 
            matrixData: {}, 
            evidenceTags: [], 
            uploadedFiles: [] 
        }]);
        setActiveScopeId(newId);
    };

    const renameScope = (id: string, name: string) => {
        setScopes(prev => prev.map(s => s.id === id ? { ...s, name } : s));
    };

    const deleteScope = (idToDelete: string) => {
        // Use functional update to ensure we have the absolute latest state
        setScopes(currentScopes => {
            const indexToDelete = currentScopes.findIndex(s => s.id === idToDelete);
            if (indexToDelete === -1) {
                console.warn(`[AuditContext] Attempted to delete non-existent scope: ${idToDelete}`);
                return currentScopes;
            }

            const remaining = currentScopes.filter(s => s.id !== idToDelete);

            // If we deleted the last remaining scope, reset to default immediately
            if (remaining.length === 0) {
                const newId = `scope_${Date.now()}`;
                const defaultScope = { 
                    id: newId, 
                    name: "", 
                    evidence: "", 
                    matrixData: {}, 
                    evidenceTags: [], 
                    uploadedFiles: [] 
                };
                // Must update activeScopeId outside this reducer to avoid conflicts, 
                // but we can schedule it.
                setTimeout(() => setActiveScopeId(newId), 0);
                return [defaultScope];
            }

            // If we deleted the CURRENTLY ACTIVE scope, we must switch.
            if (activeScopeId === idToDelete) {
                // Logic: Go to the one before it, or the first one if it was index 0
                const newIndex = Math.max(0, indexToDelete - 1);
                const nextActiveId = remaining[newIndex].id;
                setTimeout(() => setActiveScopeId(nextActiveId), 0);
            }

            return remaining;
        });
    };

    const addEvidenceTag = (tag: EvidenceTag) => {
        setEvidenceTags(prev => [...prev, tag]);
    };

    const loadKnowledgeForStandard = async (key: string) => {
        try {
            const doc = await KnowledgeStore.getDocument(key);
            if (doc) {
                setKnowledgeBase(doc.content);
                setKnowledgeFileName(doc.fileName);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) {
            console.error("KB Load Error", e);
        }
    };

    const clearKnowledge = async () => {
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        if (standardKey) {
            await KnowledgeStore.deleteDocument(standardKey);
        }
    };

    const setKnowledgeData = (content: string, fileName: string) => {
        setKnowledgeBase(content);
        setKnowledgeFileName(fileName);
    };

    const resetSession = () => {
        setStandardKey("");
        setAuditInfo(DEFAULT_AUDIT_INFO);
        setScopes([{ id: "scope_default", name: "", evidence: "", matrixData: {}, evidenceTags: [], uploadedFiles: [] }]);
        setActiveScopeId("scope_default");
        setEvidence("");
        setMatrixData({});
        setEvidenceTags([]);
        setSelectedClauses([]);
        setAnalysisResult(null);
        setSelectedFindings({});
        setFinalReportText(null);
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
    };

    const restoreSession = (data: any) => {
        if (data.standardKey) setStandardKey(data.standardKey);
        if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
        if (data.selectedClauses) setSelectedClauses(data.selectedClauses);

        if (data.scopes && data.scopes.length > 0) {
            setScopes(data.scopes);
            if(data.activeScopeId) setActiveScopeId(data.activeScopeId);
        } else if (data.evidence) {
            // Legacy Migration
            setScopes([{ id: "legacy", name: "Restored", evidence: data.evidence, matrixData: data.matrixData || {}, evidenceTags: [], uploadedFiles: [] }]);
            setActiveScopeId("legacy");
        }

        if (data.analysisResult) setAnalysisResult(data.analysisResult);
        if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
        if (data.finalReportText) setFinalReportText(data.finalReportText);

        // Trigger knowledge load
        if(data.standardKey) loadKnowledgeForStandard(data.standardKey);
    };

    return (
        <AuditContext.Provider value={{
            standards, standardKey, setStandardKey, customStandards, addCustomStandard, updateStandard, resetStandard,
            auditInfo, setAuditInfo,
            scopes, activeScopeId, activeScope, setActiveScopeId, addScope, renameScope, deleteScope,
            evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
            selectedClauses, setSelectedClauses,
            knowledgeBase, knowledgeFileName, loadKnowledgeForStandard, clearKnowledge, setKnowledgeData,
            analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings, finalReportText, setFinalReportText,
            resetSession, restoreSession
        }}>
            {children}
        </AuditContext.Provider>
    );
};

export const useAudit = () => {
    const context = useContext(AuditContext);
    if (!context) throw new Error("useAudit must be used within AuditProvider");
    return context;
};

import React, { useRef, useState } from 'react';
import { Icon, IconSelect, IconInput } from '../UI';
import { StandardsData, AuditInfo, AuditScope } from '../../types';
import { AUDIT_TYPES } from '../../constants';
import { useUI } from '../../contexts/UIContext';

interface AuditInfoFormProps {
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (k: string) => void;
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;
    onAddNewStandard: () => void;
    onOpenIntegrity: () => void;
    knowledgeFileName: string | null;
    onKnowledgeUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onClearKnowledge: () => void;
    health: { isHealthy: boolean; score: number };
    auditFieldIconColor: string;
    standardOptions: { value: string; label: string }[];

    // Scope Props
    scopes: AuditScope[];
    activeScopeId: string;
    onAddScope: (name: string) => void;
    onChangeScope: (id: string) => void;
    onRenameScope: (id: string, name: string) => void;
    onDeleteScope: (id: string) => void;
}

export const AuditInfoForm: React.FC<AuditInfoFormProps> = ({
    standards, standardKey, setStandardKey, auditInfo, setAuditInfo,
    onAddNewStandard, onOpenIntegrity,
    knowledgeFileName, onKnowledgeUpload, onClearKnowledge, health, auditFieldIconColor, standardOptions,
    scopes, activeScopeId, onAddScope, onChangeScope, onRenameScope, onDeleteScope
}) => {
    const { showToast } = useUI();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [inputValue, setInputValue] = useState(""); 
    const [editingScopeId, setEditingScopeId] = useState<string | null>(null);
    const [editName, setEditName] = useState("");

    // Logic icon
    const hasSource = !!knowledgeFileName;
    const isStandardSelected = !!standardKey && standardKey !== "ADD_NEW";
    const sourceIcon = hasSource ? "BookOpen" : "Book";

    let sourceColor = "text-gray-300 dark:text-slate-600"; 
    let sourceTooltip = "Please select an ISO Standard first to enable document upload.";
    let cursorClass = "cursor-not-allowed";

    if (hasSource) {
        sourceColor = "text-emerald-500 drop-shadow-sm";
        sourceTooltip = `Source Attached: ${knowledgeFileName}. Click to Replace.`;
        cursorClass = "cursor-pointer";
    } else if (isStandardSelected) {
        sourceColor = `${auditFieldIconColor} hover:text-indigo-600 dark:hover:text-indigo-300`;
        sourceTooltip = "Click to upload Source PDF or Word (DOCX) for better accuracy";
        cursorClass = "cursor-pointer hover:scale-110 active:scale-95";
    }

    const handleIconClick = () => {
        if (!isStandardSelected) return;
        if (fileInputRef.current) fileInputRef.current.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            onKnowledgeUpload(e);
            e.target.value = '';
        }
    };

    // --- INPUT HANDLER ---
    const handleAddKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            e.preventDefault();
            const trimmed = inputValue.trim();
            if (trimmed) {
                const existing = scopes.find(s => s.name.toLowerCase() === trimmed.toLowerCase());
                if (existing) {
                    onChangeScope(existing.id);
                    showToast(`Switched to: ${existing.name}`);
                } else {
                    onAddScope(trimmed);
                    showToast(`Added Scope: ${trimmed}`);
                }
                setInputValue(""); 
            }
        }
    };

    // --- ROBUST DELETE HANDLER ---
    const handleForceDelete = (id: string, scopeName: string) => {
        console.log(`[Delete Action] Request to delete: ${id}`);
        // Simple confirmation
        if (window.confirm(`Are you sure you want to delete the scope "${scopeName}"? This cannot be undone.`)) {
            onDeleteScope(id);
            showToast(`Deleted: ${scopeName}`);
        }
    };

    const handleRenameClick = (scope: AuditScope) => {
        setEditingScopeId(scope.id);
        setEditName(scope.name);
    };

    const saveEditing = () => {
        if (editingScopeId && editName.trim()) {
            onRenameScope(editingScopeId, editName.trim());
            showToast("Renamed successfully");
        }
        setEditingScopeId(null);
    };

    const displayScopes = scopes.filter(s => s.name && s.name.trim() !== "");

    return (
        <div className="bg-gray-50/80 dark:bg-slate-900/50 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-3 space-y-4">
            <input type="file" ref={fileInputRef} accept=".pdf,.docx,.doc,.txt" className="hidden" onChange={handleFileChange} />

            {/* SECTION 1: SCOPE */}
            <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Scope Definition</label>
                <div className="relative group/source">
                    <IconSelect 
                        icon={sourceIcon}
                        iconColor={`${sourceColor} transition-all duration-300 ${cursorClass}`}
                        value={standardKey} 
                        onChange={(e: any) => { if (e.target.value === "ADD_NEW") onAddNewStandard(); else setStandardKey(e.target.value); }} 
                        options={standardOptions} 
                        defaultText="Select ISO Standard"
                        onIconClick={handleIconClick}
                        iconTitle={sourceTooltip}
                    />

                    {hasSource && (
                        <button
                            onClick={(e) => { e.stopPropagation(); onClearKnowledge(); }}
                            className="absolute right-9 top-1/2 -translate-y-1/2 p-1.5 text-slate-400 hover:text-red-500 bg-transparent hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-all z-20 active:scale-95"
                            title="Remove Source File"
                        >
                            <Icon name="Trash2" size={14} />
                        </button>
                    )}

                    {standardKey && (
                        <button onClick={onOpenIntegrity} className={`absolute -top-1.5 -right-1.5 p-1 rounded-full shadow-lg transition-all hover:scale-110 active:scale-95 text-white ring-2 ring-white dark:ring-slate-900 ${health.isHealthy ? 'bg-emerald-500' : 'bg-orange-500'}`} title="Integrity Check">
                            <Icon name={health.isHealthy ? "CheckCircle2" : "AlertCircle"} size={10}/>
                        </button>
                    )}
                </div>

                <IconSelect icon="FileEdit" iconColor={auditFieldIconColor} value={auditInfo.type} onChange={(e: any) => setAuditInfo({...auditInfo, type: e.target.value})} options={Object.keys(AUDIT_TYPES).map(key => ({ value: key, label: key }))} defaultText="Select Audit Type" />
            </div>

            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

            {/* SECTION 2: ENTITY & DEPARTMENTS */}
            <div className="space-y-3">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Audit Context</label>
                <div className="grid grid-cols-[1.5fr_1fr] gap-2">
                    <IconInput icon="Building" iconColor={auditFieldIconColor} placeholder="Company Name" value={auditInfo.company} onChange={(e: any) => setAuditInfo({...auditInfo, company: e.target.value})} />
                    <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="SMO/ID" value={auditInfo.smo} onChange={(e: any) => setAuditInfo({...auditInfo, smo: e.target.value})} />
                </div>

                {/* --- SCOPE MANAGER --- */}
                <div className="space-y-2 pt-1">
                    {/* Creation Input */}
                    <div className="relative">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-600 dark:text-indigo-400">
                            <Icon name="Plus" size={16} />
                        </div>
                        <input
                            type="text"
                            value={inputValue}
                            placeholder="Add Scope (e.g. HR Dept) & Enter..."
                            onChange={(e) => setInputValue(e.target.value)}
                            onKeyDown={handleAddKeyDown}
                            className="w-full pl-10 pr-3 py-2.5 bg-white dark:bg-slate-950 border border-indigo-100 dark:border-slate-700 rounded-xl text-xs font-bold text-slate-700 dark:text-slate-300 placeholder-indigo-300 dark:placeholder-slate-600 outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/10 transition-all shadow-sm"
                        />
                    </div>

                    {/* List of Scopes */}
                    <div className="flex flex-col gap-1.5 max-h-40 overflow-y-auto custom-scrollbar px-0.5">
                        {displayScopes.length > 0 ? displayScopes.map(s => {
                            const isActive = activeScopeId === s.id;
                            const isEditing = editingScopeId === s.id;

                            // ARCHITECTURE FIX: SEPARATE SIBLINGS FOR CLICK AND ACTION TO PREVENT EVENT BUBBLING
                            return (
                                <div 
                                    key={s.id}
                                    data-testid={`scope-row-${s.id}`}
                                    className={`flex items-stretch rounded-lg border transition-all duration-200 select-none overflow-hidden ${isActive ? 'bg-indigo-600 border-indigo-600 shadow-md transform scale-[1.01]' : 'bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 hover:border-indigo-300 dark:hover:border-slate-600'}`}
                                >
                                    {/* ZONE 1: SELECTION (CLICKABLE) */}
                                    <div 
                                        onClick={() => !isEditing && onChangeScope(s.id)}
                                        className="flex-1 flex items-center gap-2 px-2 py-2 cursor-pointer min-w-0"
                                    >
                                        <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_4px_rgba(255,255,255,0.8)]' : 'bg-slate-300 dark:bg-slate-600'}`}></div>

                                        {isEditing ? (
                                            <input 
                                                autoFocus
                                                className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs font-bold px-1 rounded outline-none"
                                                value={editName}
                                                onChange={e => setEditName(e.target.value)}
                                                onKeyDown={e => e.key === 'Enter' && saveEditing()}
                                                onBlur={saveEditing}
                                                onClick={e => e.stopPropagation()} 
                                            />
                                        ) : (
                                            <span className={`text-xs truncate font-bold ${isActive ? 'text-white' : 'text-slate-600 dark:text-slate-300'}`}>
                                                {s.name}
                                            </span>
                                        )}
                                    </div>

                                    {/* ZONE 2: ACTIONS (ISOLATED SIBLING) */}
                                    {!isEditing && (
                                        <div className={`flex items-center gap-0.5 px-1 border-l ${isActive ? 'border-indigo-500 bg-indigo-700' : 'border-gray-100 dark:border-slate-800 bg-gray-50 dark:bg-slate-800/50'}`}>
                                            <button 
                                                type="button"
                                                onClick={(e) => { e.stopPropagation(); handleRenameClick(s); }}
                                                className={`p-1.5 rounded transition-colors cursor-pointer flex items-center justify-center h-full ${isActive ? 'text-indigo-200 hover:text-white hover:bg-indigo-500' : 'text-slate-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/30'}`}
                                                title="Rename"
                                            >
                                                <Icon name="FileEdit" size={12}/>
                                            </button>

                                            {/* THE DELETE BUTTON - FULLY ISOLATED */}
                                            <button 
                                                type="button"
                                                data-testid={`delete-scope-${s.id}`}
                                                onClick={(e) => { 
                                                    // Redundant safety, but good to have
                                                    e.preventDefault(); 
                                                    e.stopPropagation(); 
                                                    handleForceDelete(s.id, s.name); 
                                                }}
                                                className={`p-1.5 rounded transition-colors cursor-pointer flex items-center justify-center h-full ${isActive ? 'text-indigo-200 hover:text-white hover:bg-red-500' : 'text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30'}`}
                                                title="Delete Scope"
                                            >
                                                <Icon name="Trash2" size={12}/>
                                            </button>
                                        </div>
                                    )}
                                </div>
                            );
                        }) : (
                            <div className="text-center py-3 text-[10px] text-slate-400 italic bg-gray-50 dark:bg-slate-800/30 rounded-lg border border-dashed border-gray-200 dark:border-slate-700">
                                No scopes yet. Type above to create one.
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

            {/* SECTION 3: PERSONNEL */}
            <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Personnel</label>
                <div className="grid grid-cols-2 gap-2">
                     <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                     <IconInput icon="User" iconColor={auditFieldIconColor} placeholder="Interviewee" value={auditInfo.interviewee} onChange={(e: any) => setAuditInfo({...auditInfo, interviewee: e.target.value})} />
                </div>
            </div>
        </div>
    );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { StandardsData, AuditInfo, AuditScope, Standard, MatrixRow, EvidenceTag, AnalysisResult } from '../types';
import { DEFAULT_AUDIT_INFO, STANDARDS_DATA, INITIAL_EVIDENCE } from '../constants';
import { KnowledgeStore } from '../services/knowledgeStore';

interface AuditContextType {
    // Standard
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (key: string) => void;
    customStandards: StandardsData;
    addCustomStandard: (key: string, std: Standard) => void;
    updateStandard: (std: Standard) => void;
    resetStandard: (key: string) => void;

    // Audit Info
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;

    // Scopes (Departments)
    scopes: AuditScope[];
    activeScopeId: string;
    activeScope: AuditScope | undefined;
    setActiveScopeId: (id: string) => void;
    addScope: (name: string) => void;
    renameScope: (id: string, name: string) => void;
    deleteScope: (id: string) => void;

    // Active Data (Derived from activeScope)
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    evidenceTags: EvidenceTag[];
    addEvidenceTag: (tag: EvidenceTag) => void;

    // Selections
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;

    // Knowledge Base
    knowledgeBase: string | null;
    knowledgeFileName: string | null;
    loadKnowledgeForStandard: (key: string) => Promise<void>;
    clearKnowledge: () => void;
    setKnowledgeData: (content: string, fileName: string) => void;

    // Results
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    finalReportText: string | null;
    setFinalReportText: (text: string | null) => void;

    // Actions
    resetSession: () => void;
    restoreSession: (data: any) => void;
}

const AuditContext = createContext<AuditContextType | undefined>(undefined);

export const AuditProvider = ({ children }: { children: ReactNode }) => {
    // --- STATE ---
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);

    // Scopes
    const [scopes, setScopes] = useState<AuditScope[]>([
        { id: "scope_default", name: "General Scope", evidence: "", matrixData: {}, evidenceTags: [], uploadedFiles: [] }
    ]);
    const [activeScopeId, setActiveScopeId] = useState<string>("scope_default");

    // Active View Data (Synced with Active Scope)
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [matrixData, setMatrixData] = useState<Record<string, MatrixRow[]>>({});
    const [evidenceTags, setEvidenceTags] = useState<EvidenceTag[]>([]);

    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // KB
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    // Analysis
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);

    const standards = { ...STANDARDS_DATA, ...customStandards };

    // Safe fallback: if activeScopeId not found, use first scope temporarily
    const activeScope = scopes.find(s => s.id === activeScopeId) || scopes[0];

    // --- WATCHDOG: Ensure Active Scope Validity ---
    // This effect runs whenever scopes list changes (e.g. deletion).
    // If the active ID is dead, it auto-switches to a valid one.
    useEffect(() => {
        // 1. Safety check: Ensure at least one scope exists
        if (scopes.length === 0) {
             const newId = `scope_${Date.now()}`;
             setScopes([{ 
                 id: newId, 
                 name: "New Scope", 
                 evidence: "", 
                 matrixData: {}, 
                 evidenceTags: [], 
                 uploadedFiles: [] 
             }]);
             setActiveScopeId(newId);
             return;
        }

        // 2. Validate Active ID
        const isValid = scopes.some(s => s.id === activeScopeId);
        if (!isValid) {
            // Auto-heal: Switch to the first available scope
            console.warn(`[AuditContext] Active scope ${activeScopeId} deleted/invalid. Switching to ${scopes[0].id}`);
            setActiveScopeId(scopes[0].id);
        }
    }, [scopes, activeScopeId]);

    // --- SYNC EFFECTS ---
    // Save current view state to the active scope object whenever it changes
    useEffect(() => {
        if (!activeScopeId) return;

        setScopes(prev => prev.map(s => {
            if (s.id === activeScopeId) {
                // Only update if changed to avoid infinite loop
                if (s.evidence !== evidence || s.matrixData !== matrixData || s.evidenceTags !== evidenceTags) {
                    return { ...s, evidence, matrixData, evidenceTags };
                }
            }
            return s;
        }));
    }, [evidence, matrixData, evidenceTags, activeScopeId]);

    // Load scope data into view when ID changes
    useEffect(() => {
        const target = scopes.find(s => s.id === activeScopeId);
        if (target) {
            setEvidence(target.evidence || "");
            setMatrixData(target.matrixData || {});
            setEvidenceTags(target.evidenceTags || []);
        }
    }, [activeScopeId]); // Don't include scopes here to avoid reload loops

    // --- ACTIONS ---

    const addCustomStandard = (key: string, std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [key]: std }));
    };

    const updateStandard = (std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    };

    const resetStandard = (key: string) => {
        setCustomStandards(prev => {
            const next = { ...prev };
            delete next[key];
            return next;
        });
    };

    const addScope = (name: string) => {
        const newId = `scope_${Date.now()}`;
        setScopes(prev => [...prev, { 
            id: newId, 
            name, 
            evidence: "", 
            matrixData: {}, 
            evidenceTags: [], 
            uploadedFiles: [] 
        }]);
        setActiveScopeId(newId);
    };

    const renameScope = (id: string, name: string) => {
        setScopes(prev => prev.map(s => s.id === id ? { ...s, name } : s));
    };

    const deleteScope = (idToDelete: string) => {
        // Simplified logic: Just remove it. 
        // The Watchdog useEffect will handle the active ID switching safely.
        setScopes(currentScopes => {
            if (currentScopes.length <= 1) {
                alert("Cannot delete the last scope.");
                return currentScopes;
            }
            return currentScopes.filter(s => s.id !== idToDelete);
        });
    };

    const addEvidenceTag = (tag: EvidenceTag) => {
        setEvidenceTags(prev => [...prev, tag]);
    };

    const loadKnowledgeForStandard = async (key: string) => {
        try {
            const doc = await KnowledgeStore.getDocument(key);
            if (doc) {
                setKnowledgeBase(doc.content);
                setKnowledgeFileName(doc.fileName);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) {
            console.error("KB Load Error", e);
        }
    };

    const clearKnowledge = async () => {
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        if (standardKey) {
            await KnowledgeStore.deleteDocument(standardKey);
        }
    };

    const setKnowledgeData = (content: string, fileName: string) => {
        setKnowledgeBase(content);
        setKnowledgeFileName(fileName);
    };

    const resetSession = () => {
        setStandardKey("");
        setAuditInfo(DEFAULT_AUDIT_INFO);
        setScopes([{ id: "scope_default", name: "General Scope", evidence: "", matrixData: {}, evidenceTags: [], uploadedFiles: [] }]);
        setActiveScopeId("scope_default");
        setEvidence("");
        setMatrixData({});
        setEvidenceTags([]);
        setSelectedClauses([]);
        setAnalysisResult(null);
        setSelectedFindings({});
        setFinalReportText(null);
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
    };

    const restoreSession = (data: any) => {
        if (data.standardKey) setStandardKey(data.standardKey);
        if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
        if (data.selectedClauses) setSelectedClauses(data.selectedClauses);

        if (data.scopes && data.scopes.length > 0) {
            setScopes(data.scopes);
            if(data.activeScopeId) setActiveScopeId(data.activeScopeId);
        } else if (data.evidence) {
            // Legacy Migration
            setScopes([{ id: "legacy", name: "Restored", evidence: data.evidence, matrixData: data.matrixData || {}, evidenceTags: [], uploadedFiles: [] }]);
            setActiveScopeId("legacy");
        }

        if (data.analysisResult) setAnalysisResult(data.analysisResult);
        if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
        if (data.finalReportText) setFinalReportText(data.finalReportText);

        // Trigger knowledge load
        if(data.standardKey) loadKnowledgeForStandard(data.standardKey);
    };

    return (
        <AuditContext.Provider value={{
            standards, standardKey, setStandardKey, customStandards, addCustomStandard, updateStandard, resetStandard,
            auditInfo, setAuditInfo,
            scopes, activeScopeId, activeScope, setActiveScopeId, addScope, renameScope, deleteScope,
            evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
            selectedClauses, setSelectedClauses,
            knowledgeBase, knowledgeFileName, loadKnowledgeForStandard, clearKnowledge, setKnowledgeData,
            analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings, finalReportText, setFinalReportText,
            resetSession, restoreSession
        }}>
            {children}
        </AuditContext.Provider>
    );
};

export const useAudit = () => {
    const context = useContext(AuditContext);
    if (!context) throw new Error("useAudit must be used within AuditProvider");
    return context;
};

import React, { useRef, useState } from 'react';
import { Icon, IconSelect, IconInput } from '../UI';
import { StandardsData, AuditInfo, AuditScope } from '../../types';
import { AUDIT_TYPES } from '../../constants';
import { useUI } from '../../contexts/UIContext';

interface AuditInfoFormProps {
    standards: StandardsData;
    standardKey: string;
    setStandardKey: (k: string) => void;
    auditInfo: AuditInfo;
    setAuditInfo: (info: AuditInfo) => void;
    onAddNewStandard: () => void;
    onOpenIntegrity: () => void;
    knowledgeFileName: string | null;
    onKnowledgeUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onClearKnowledge: () => void;
    health: { isHealthy: boolean; score: number };
    auditFieldIconColor: string;
    standardOptions: { value: string; label: string }[];

    // Scope Props
    scopes: AuditScope[];
    activeScopeId: string;
    onAddScope: (name: string) => void;
    onChangeScope: (id: string) => void;
    onRenameScope: (id: string, name: string) => void;
    onDeleteScope: (id: string) => void;
}

export const AuditInfoForm: React.FC<AuditInfoFormProps> = ({
    standards, standardKey, setStandardKey, auditInfo, setAuditInfo,
    onAddNewStandard, onOpenIntegrity,
    knowledgeFileName, onKnowledgeUpload, onClearKnowledge, health, auditFieldIconColor, standardOptions,
    scopes, activeScopeId, onAddScope, onChangeScope, onRenameScope, onDeleteScope
}) => {
    const { showToast } = useUI();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const [inputValue, setInputValue] = useState(""); 
    const [editingScopeId, setEditingScopeId] = useState<string | null>(null);
    const [editName, setEditName] = useState("");

    // Logic icon
    const hasSource = !!knowledgeFileName;
    const isStandardSelected = !!standardKey && standardKey !== "ADD_NEW";
    const sourceIcon = hasSource ? "BookOpen" : "Book";

    let sourceColor = "text-gray-300 dark:text-slate-600"; 
    let sourceTooltip = "Please select an ISO Standard first to enable document upload.";
    let cursorClass = "cursor-not-allowed";

    if (hasSource) {
        sourceColor = "text-emerald-500 drop-shadow-sm";
        sourceTooltip = `Source Attached: ${knowledgeFileName}. Click to Replace.`;
        cursorClass = "cursor-pointer";
    } else if (isStandardSelected) {
        sourceColor = `${auditFieldIconColor} hover:text-indigo-600 dark:hover:text-indigo-300`;
        sourceTooltip = "Click to upload Source PDF or Word (DOCX) for better accuracy";
        cursorClass = "cursor-pointer hover:scale-110 active:scale-95";
    }

    const handleIconClick = () => {
        if (!isStandardSelected) return;
        if (fileInputRef.current) fileInputRef.current.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            onKnowledgeUpload(e);
            e.target.value = '';
        }
    };

    // --- INPUT HANDLER ---
    const handleAddKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            e.preventDefault();
            const trimmed = inputValue.trim();
            if (trimmed) {
                const existing = scopes.find(s => s.name.toLowerCase() === trimmed.toLowerCase());
                if (existing) {
                    onChangeScope(existing.id);
                    showToast(`Switched to: ${existing.name}`);
                } else {
                    onAddScope(trimmed);
                    showToast(`Added Scope: ${trimmed}`);
                }
                setInputValue(""); 
            }
        }
    };

    // --- ROBUST DELETE HANDLER ---
    const handleForceDelete = (e: React.MouseEvent, id: string, scopeName: string) => {
        // Critical: Stop everything
        e.preventDefault();
        e.stopPropagation();

        console.log(`[Delete Action] Triggered for: ${id}`);

        if (window.confirm(`Delete scope "${scopeName}"?`)) {
            onDeleteScope(id);
            showToast(`Deleted: ${scopeName}`);
        }
    };

    const handleRenameClick = (scope: AuditScope) => {
        setEditingScopeId(scope.id);
        setEditName(scope.name);
    };

    const saveEditing = () => {
        if (editingScopeId && editName.trim()) {
            onRenameScope(editingScopeId, editName.trim());
            showToast("Renamed successfully");
        }
        setEditingScopeId(null);
    };

    const displayScopes = scopes.filter(s => s.name && s.name.trim() !== "");

    return (
        <div className="bg-gray-50/80 dark:bg-slate-900/50 rounded-2xl border border-gray-100 dark:border-slate-800 shadow-sm p-3 space-y-4">
            <input type="file" ref={fileInputRef} accept=".pdf,.docx,.doc,.txt" className="hidden" onChange={handleFileChange} />

            {/* SECTION 1: SCOPE */}
            <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Scope Definition</label>
                <div className="relative group/source">
                    <IconSelect 
                        icon={sourceIcon}
                        iconColor={`${sourceColor} transition-all duration-300 ${cursorClass}`}
                        value={standardKey} 
                        onChange={(e: any) => { if (e.target.value === "ADD_NEW") onAddNewStandard(); else setStandardKey(e.target.value); }} 
                        options={standardOptions} 
                        defaultText="Select ISO Standard"
                        onIconClick={handleIconClick}
                        iconTitle={sourceTooltip}
                    />

                    {hasSource && (
                        <button
                            onClick={(e) => { e.stopPropagation(); onClearKnowledge(); }}
                            className="absolute right-9 top-1/2 -translate-y-1/2 p-1.5 text-slate-400 hover:text-red-500 bg-transparent hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-all z-20 active:scale-95"
                            title="Remove Source File"
                        >
                            <Icon name="Trash2" size={14} />
                        </button>
                    )}

                    {standardKey && (
                        <button onClick={onOpenIntegrity} className={`absolute -top-1.5 -right-1.5 p-1 rounded-full shadow-lg transition-all hover:scale-110 active:scale-95 text-white ring-2 ring-white dark:ring-slate-900 ${health.isHealthy ? 'bg-emerald-500' : 'bg-orange-500'}`} title="Integrity Check">
                            <Icon name={health.isHealthy ? "CheckCircle2" : "AlertCircle"} size={10}/>
                        </button>
                    )}
                </div>

                <IconSelect icon="FileEdit" iconColor={auditFieldIconColor} value={auditInfo.type} onChange={(e: any) => setAuditInfo({...auditInfo, type: e.target.value})} options={Object.keys(AUDIT_TYPES).map(key => ({ value: key, label: key }))} defaultText="Select Audit Type" />
            </div>

            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

            {/* SECTION 2: ENTITY & DEPARTMENTS */}
            <div className="space-y-3">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Audit Context</label>
                <div className="grid grid-cols-[1.5fr_1fr] gap-2">
                    <IconInput icon="Building" iconColor={auditFieldIconColor} placeholder="Company Name" value={auditInfo.company} onChange={(e: any) => setAuditInfo({...auditInfo, company: e.target.value})} />
                    <IconInput icon="Tag" iconColor={auditFieldIconColor} placeholder="SMO/ID" value={auditInfo.smo} onChange={(e: any) => setAuditInfo({...auditInfo, smo: e.target.value})} />
                </div>

                {/* --- SCOPE MANAGER --- */}
                <div className="space-y-2 pt-1">
                    {/* Creation Input */}
                    <div className="relative">
                        <div className="absolute left-3 top-1/2 -translate-y-1/2 pointer-events-none text-indigo-600 dark:text-indigo-400">
                            <Icon name="Plus" size={16} />
                        </div>
                        <input
                            type="text"
                            value={inputValue}
                            placeholder="Add Scope (e.g. HR Dept) & Enter..."
                            onChange={(e) => setInputValue(e.target.value)}
                            onKeyDown={handleAddKeyDown}
                            className="w-full pl-10 pr-3 py-2.5 bg-white dark:bg-slate-950 border border-indigo-100 dark:border-slate-700 rounded-xl text-xs font-bold text-slate-700 dark:text-slate-300 placeholder-indigo-300 dark:placeholder-slate-600 outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/10 transition-all shadow-sm"
                        />
                    </div>

                    {/* List of Scopes */}
                    <div className="flex flex-col gap-1.5 max-h-40 overflow-y-auto custom-scrollbar px-0.5">
                        {displayScopes.length > 0 ? displayScopes.map(s => {
                            const isActive = activeScopeId === s.id;
                            const isEditing = editingScopeId === s.id;

                            // ARCHITECTURE FIX: SEPARATE SIBLINGS FOR CLICK AND ACTION TO PREVENT EVENT BUBBLING
                            return (
                                <div 
                                    key={s.id}
                                    data-testid={`scope-row-${s.id}`}
                                    className={`flex items-stretch rounded-lg border transition-all duration-200 select-none overflow-hidden ${isActive ? 'bg-indigo-600 border-indigo-600 shadow-md transform scale-[1.01]' : 'bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800 hover:border-indigo-300 dark:hover:border-slate-600'}`}
                                >
                                    {/* ZONE 1: SELECTION (CLICKABLE) */}
                                    <div 
                                        onClick={() => !isEditing && onChangeScope(s.id)}
                                        className="flex-1 flex items-center gap-2 px-2 py-2 cursor-pointer min-w-0"
                                    >
                                        <div className={`flex-shrink-0 w-1.5 h-1.5 rounded-full ${isActive ? 'bg-white shadow-[0_0_4px_rgba(255,255,255,0.8)]' : 'bg-slate-300 dark:bg-slate-600'}`}></div>

                                        {isEditing ? (
                                            <input 
                                                autoFocus
                                                className="w-full bg-white dark:bg-slate-800 text-slate-900 dark:text-white text-xs font-bold px-1 rounded outline-none"
                                                value={editName}
                                                onChange={e => setEditName(e.target.value)}
                                                onKeyDown={e => e.key === 'Enter' && saveEditing()}
                                                onBlur={saveEditing}
                                                onClick={e => e.stopPropagation()} 
                                            />
                                        ) : (
                                            <span className={`text-xs truncate font-bold ${isActive ? 'text-white' : 'text-slate-600 dark:text-slate-300'}`}>
                                                {s.name}
                                            </span>
                                        )}
                                    </div>

                                    {/* ZONE 2: ACTIONS (ISOLATED SIBLING) */}
                                    {!isEditing && (
                                        <div className={`flex items-center gap-0.5 px-1 border-l ${isActive ? 'border-indigo-500 bg-indigo-700' : 'border-gray-100 dark:border-slate-800 bg-gray-50 dark:bg-slate-800/50'}`}>
                                            <button 
                                                type="button"
                                                onClick={(e) => { e.stopPropagation(); handleRenameClick(s); }}
                                                className={`p-1.5 rounded transition-colors cursor-pointer flex items-center justify-center h-full z-10 ${isActive ? 'text-indigo-200 hover:text-white hover:bg-indigo-500' : 'text-slate-400 hover:text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/30'}`}
                                                title="Rename"
                                            >
                                                <Icon name="FileEdit" size={12}/>
                                            </button>

                                            {/* THE DELETE BUTTON - FULLY ISOLATED */}
                                            {/* Changed to onMouseDown to catch event earlier than blur/click race conditions */}
                                            <button 
                                                type="button"
                                                data-testid={`delete-scope-${s.id}`}
                                                onMouseDown={(e) => handleForceDelete(e, s.id, s.name)}
                                                className={`p-1.5 rounded transition-colors cursor-pointer flex items-center justify-center h-full z-10 ${isActive ? 'text-indigo-200 hover:text-white hover:bg-red-500' : 'text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/30'}`}
                                                title="Delete Scope"
                                            >
                                                <Icon name="Trash2" size={12}/>
                                            </button>
                                        </div>
                                    )}
                                </div>
                            );
                        }) : (
                            <div className="text-center py-3 text-[10px] text-slate-400 italic bg-gray-50 dark:bg-slate-800/30 rounded-lg border border-dashed border-gray-200 dark:border-slate-700">
                                No scopes yet. Type above to create one.
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="h-px bg-gray-200 dark:bg-slate-700/50"></div>

            {/* SECTION 3: PERSONNEL */}
            <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase px-1">Personnel</label>
                <div className="grid grid-cols-2 gap-2">
                     <IconInput icon="AuditUser" iconColor={auditFieldIconColor} placeholder="Lead Auditor" value={auditInfo.auditor} onChange={(e: any) => setAuditInfo({...auditInfo, auditor: e.target.value})} />
                     <IconInput icon="User" iconColor={auditFieldIconColor} placeholder="Interviewee" value={auditInfo.interviewee} onChange={(e: any) => setAuditInfo({...auditInfo, interviewee: e.target.value})} />
                </div>
            </div>
        </div>
    );
};
